sys_script_client.script:
function onLoad() {
    /**
	GEM/Duypd - 14.05.2026:
	TAM/Sprint 3/Story TAM_43
	When table loading, configure acceptance criteria handling:

	Store mandatory fields in array fieldMandatory
	Store readonly fields in array fieldReadonly
	Use g_form to set field mandatory and readonly dynamically.
    */

    var fieldMandatory = ["u_submit_date", "u_skills", "u_bid_source", "u_bid_recruit_id", "u_submitter", "u_bid_candidate_id"];
    var fieldReadonly = ["u_bid_id", "u_actual_start_date", "u_bid_candidate_id.u_email", "u_bid_candidate_id.u_username", "time_of_submitting", "u_bid_tof", "u_ytd", "u_duration_of_ticket", "u_candidate_username", "u_candidate_email", "candidate_phone_number"];

    fieldMandatory.forEach(function(field) {
        g_form.setMandatory(field, true);
    });

    fieldReadonly.forEach(function(field) {
        g_form.setReadOnly(field, true);
    });

}
